const root = $json || {};
const body = root.body || root || {};

function asString(v) {
  if (v === undefined || v === null) return '';
  if (typeof v === 'string') return v.trim();
  try { return JSON.stringify(v, null, 2); } catch { return String(v); }
}

function parseMaybeJson(v) {
  if (v === undefined || v === null) return null;
  if (typeof v === 'object') return v;
  const s = String(v).trim();
  if (!s) return null;
  try { return JSON.parse(s); } catch { return null; }
}

function renderTemplate(template, vars) {
  return String(template || '').replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (_, key) => {
    const val = vars[key];
    return val === undefined || val === null ? '' : String(val);
  });
}

const RECIPE_REGISTRY = {
  'hot_clone@v1': {
    defaults: {
      workflow_id_for_credits: 'flow_farm_copy',
      model: 'sora2',
      aspect_ratio: 'portrait',
      n_frames: '15'
    },
    routes: {
      prompt_callback_url: 'https://www.atomx.top/api/webhook/replication/prompt',
      sora_start_webhook: 'https://hooks.atomx.top/webhook/sora_web'
    },
    prompts: {
      clone_system: `Role

你是一位世界级的 AI 视频创意总监（AI Video Director）。
你擅长把产品信息嵌入“爆款分镜逻辑”，并输出可直接用于 Sora2 的分镜提示词。

Inputs

1. Source Blueprint（爆款拆解，包含 visual_specs 和 abstract_logic）
2. Target Product Info（新产品信息）
3. Target Duration = {{duration}} 秒
4. Locale Config
   - Target Country/Region = {{country_region}}
   - Target City/Style = {{city_style_fallback}}
   - Target Language = {{target_language}}

Task

阅读 Source Blueprint 每个分镜，使用 abstract_logic 的 universal_instruction，
将 Target Product 填入分镜，生成一份全新的、逻辑自洽的“{{target_language}}”视频生成提示词，
总时长严格为 {{duration}} 秒，并且场景必须发生在 {{country_region}}（及其城市风格）。

Locale Hard Rules

A) Country/Region Scene Lock
- 所有场景必须符合目标国家/地区的真实生活语境（建筑、室内陈设、街景、服饰、道具、光线氛围）。
- 如果提供了城市/风格，则优先贴近该城市的风格元素。
- 禁止出现与目标国家明显冲突的符号。

B) Language Lock
- 所有口播/对白（如果存在）必须是 Target Language。
- 画风不受语言影响，只有声音内容受语言约束。

C) No On-Screen Text Lock
- 画面中禁止出现任何形式的文字或字符，包括字幕、贴纸字、标题卡、价格牌、包装文字、标签文字、UI 文字、路牌文字、门店招牌文字、衣物字母、书籍报纸文字、屏幕弹窗文字、水印、LOGO 文字、社媒界面文字。
- 若现实环境中不可避免出现文字，必须改写为无法识别的抽象图形、色块或模糊纹理。
- 禁止使用“后期叠字/加字幕/屏幕文字/标题卡/贴纸文字”等任何形式的指令。
- 如需表达卖点、价格、CTA、步骤，只能通过动作、道具对比、表情、镜头语言、环境音、口播完成。

Transformation Logic

对每个分镜必须执行：
1. 读取 abstract_logic
2. 用新产品完成同一逻辑
3. 保留原片运镜与节奏，但画面元素必须符合目标国家/地区

Pacing Adaptation

你必须根据 Source Blueprint 的总时长与 Target Duration 做适配：
- 误差 ±2 秒：不改分镜结构
- 需要压缩：保留 Hook / Core Benefit / End，压缩弱镜头
- 需要延展：延长高光时刻、空镜细节、慢动作、动作节奏

Constraints
- 优先保持原有分镜顺序与镜头逻辑
- 描写必须镜头友好、动作可执行、画面细节明确
- 情绪基调与叙事节奏保持一致
- 最终输出必须完全使用 Target Language，包括结构标签和镜头术语
- 不允许混用多种语言
- 不得包含任何将显示在画面上的文字内容

Output Format

只输出一段完整提示词，不要解释，不要输出 JSON，不要输出额外说明。
输出必须是一个单独的文本块，并遵守下面结构（结构标题也必须使用 Target Language）：

【Style Tags】
Art style / Type:
Image quality:
Mood / Atmosphere:
Scene country / city:

【Storyboard】
Shot 1 (00:00 - 00:XX):
Camera movement:
Main subject action:
Product presentation:
Environment / set dressing:
Lighting:
Voiceover / ambient sound:

Shot 2 (00:XX - 00:XX):
... 按 Source Blueprint 顺序输出直到结束。`,
      clone_user: `产品信息：
{{product_info_text}}

Target Language: {{target_language}}

爆款视频拆解报告：
{{blueprint_text}}

时长：{{duration}}
国家/地区：{{country_region}}
城市/风格：{{city_style_fallback}}`
    }
  }
};

const productInfoRaw = body['产品信息'] ?? body.product_info ?? body.productInfo ?? '';
const productInfoObj = parseMaybeJson(productInfoRaw);
const blueprintRaw = body['爆款视频拆解报告'] ?? body.blueprint ?? body.source_blueprint ?? {};
const blueprintObj = parseMaybeJson(blueprintRaw) || blueprintRaw || {};

const targetLanguage = asString(body['Target Language'] ?? body.target_language ?? body.language ?? 'en');
const duration = asString(body['时长'] ?? body.duration ?? body.target_duration ?? '15');
const countryRegion = asString(body['国家/地区'] ?? body.country_region ?? body.country ?? 'us');
const cityStyle = asString(body['城市/风格'] ?? body.city_style ?? body.city ?? '');
const productName = asString(
  body.product_name ??
  body['产品名称'] ??
  productInfoObj?.product_name ??
  productInfoObj?.name ??
  ''
);

const recipeId = asString(body.recipe_id ?? 'hot_clone');
const recipeVersion = asString(body.recipe_version ?? 'v1');
const recipeKey = `${recipeId}@${recipeVersion}`;
const recipe = RECIPE_REGISTRY[recipeKey] || RECIPE_REGISTRY['hot_clone@v1'];

const promptOverrides = parseMaybeJson(body.prompt_overrides) || {};
const recipeVars = {
  product_info_text: productInfoObj ? JSON.stringify(productInfoObj, null, 2) : asString(productInfoRaw),
  blueprint_text: typeof blueprintObj === 'string' ? blueprintObj : JSON.stringify(blueprintObj, null, 2),
  target_language: targetLanguage,
  duration,
  country_region: countryRegion,
  city_style: cityStyle,
  city_style_fallback: cityStyle || 'auto'
};

const cloneSystemTemplate = asString(
  promptOverrides.clone_system ??
  body.clone_system_prompt ??
  recipe.prompts.clone_system
);
const cloneUserTemplate = asString(
  promptOverrides.clone_user ??
  body.clone_user_prompt ??
  recipe.prompts.clone_user
);

const cloneSystemPrompt = renderTemplate(cloneSystemTemplate, recipeVars);
const cloneUserPrompt = renderTemplate(cloneUserTemplate, recipeVars);

const normalized = {
  ...root,
  body,
  product_info_text: recipeVars.product_info_text,
  product_info_obj: productInfoObj || {},
  blueprint_text: recipeVars.blueprint_text,
  blueprint_obj: typeof blueprintObj === 'object' && blueprintObj ? blueprintObj : {},
  target_language: targetLanguage,
  duration,
  country_region: countryRegion,
  city_style: cityStyle,
  product_name: productName,

  recipe_id: recipeId,
  recipe_version: recipeVersion,
  recipe_key: recipeKey,
  recipe_found: !!RECIPE_REGISTRY[recipeKey],
  prompt_overrides: promptOverrides,
  clone_system_prompt: cloneSystemPrompt,
  clone_user_prompt: cloneUserPrompt,

  callback_url: asString(body.callback_url ?? body.callbackUrl ?? ''),
  prompt_callback_url: body.prompt_callback_url
    ? asString(body.prompt_callback_url)
    : (body.callback_url || body.callbackUrl
        ? asString(body.callback_url ?? body.callbackUrl ?? '') + '/prompt'
        : asString(recipe.routes.prompt_callback_url ?? '')),
  sora_provider: asString(body.sora_provider ?? 'kie'),
  replication_id: asString(body.replication_id ?? body.task_id ?? body.taskId ?? ''),
  product_id: asString(body.product_id ?? ''),
  script_id: asString(body.script_id ?? ''),
  user_id: asString(body.user_id ?? ''),
  image_1_token: asString(body.image_1_token ?? ''),
  image_url: asString(body.image_url ?? body.product_image_url ?? ''),
  api_key: asString(body.api_key ?? ''),
  workflow_id_for_credits: asString(body.workflow_id_for_credits ?? recipe.defaults.workflow_id_for_credits ?? 'flow_prompt_farm'),
  n_frames: asString(body.n_frames ?? recipe.defaults.n_frames ?? ''),
  aspect_ratio: asString(body.aspect_ratio ?? recipe.defaults.aspect_ratio ?? 'portrait'),
  model: asString(body.model ?? recipe.defaults.model ?? 'sora2')
};

return [{ json: normalized }];

const std = $('标准化输入').first()?.json || {};
const j = { ...std, ...$input.first()?.json || {} };
const raw = String(j.output || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');

if (!raw.trim()) throw new Error('没有找到 output 文本');

const productName = String(j.product_name || j['产品名称'] || '').trim();
const language = String(j.target_language || j.language || j['视频语言'] || '').trim();

function cleanBlock(s) {
  return String(s || '')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .trim();
}

let art = '';
let render = '';
let mood = '';

const lines = raw.split('\n');
const metaLine = lines
  .map(l => l.trim())
  .filter(Boolean)
  .find(l => /Art Style/i.test(l) && /Image quality|Render Quality/i.test(l) && /Mood/i.test(l)) || '';

if (metaLine) {
  const artMatch = metaLine.match(/Art Style\s*\/\s*Type\s*:\s*([^\n,]+)/i) || metaLine.match(/Art Style\]\*{0,2}\s*([^,]+)\s*,/i);
  const rqMatch  = metaLine.match(/Image quality\s*:\s*([^\n,]+)/i) || metaLine.match(/Render Quality\]\*{0,2}\s*([^,]+)\s*,/i);
  const moodMatch= metaLine.match(/Mood\s*\/\s*Atmosphere\s*:\s*([^\n]+)/i) || metaLine.match(/Mood\]\*{0,2}\s*([^.\n]+)\.?/i);
  art = cleanBlock(artMatch?.[1]);
  render = cleanBlock(rqMatch?.[1]);
  mood = cleanBlock(moodMatch?.[1]);
} else {
  const txt = raw;
  const artCn = txt.match(/画风\/类型：\s*([^\n]+)/);
  const rqCn  = txt.match(/画质：\s*([^\n]+)/);
  const moodCn= txt.match(/氛围：\s*([^\n]+)/);
  art = cleanBlock(artCn?.[1]);
  render = cleanBlock(rqCn?.[1]);
  mood = cleanBlock(moodCn?.[1]);
}

const shots = [];

const shotEnRegex = /\*{0,2}Shot\s+(\d+)\s*\(([^)]+)\)\s*:?\*{0,2}\s*([\s\S]*?)(?=(?:\n\s*\n)?\*{0,2}Shot\s+\d+\s*\(|$)/gi;
const shotCnRegex = /镜头\s*(\d+)\s*[（(]([^）)]+)[）)]\s*[:：]\s*([\s\S]*?)(?=\n\s*镜头\s*\d+\s*[（(]|$)/g;

function normalizeTimeRange(t) {
  const timeRange = cleanBlock(t);
  if (!timeRange) return '';
  return timeRange.includes('-') ? timeRange : `${timeRange} - ${timeRange}`;
}

function replacePlaceholders(body) {
  let b = body;
  if (productName) b = b.replace(/\b\[HERO_PRODUCT\]\b/g, productName);
  b = b.replace(/\b\[USER\/MODEL\]\b/g, 'a relatable on-camera creator');
  return b;
}

function collectByRegex(regex) {
  let m;
  while ((m = regex.exec(raw)) !== null) {
    const no = Number(m[1]);
    const timeRange = normalizeTimeRange(m[2]);
    let body = cleanBlock(m[3]);
    body = replacePlaceholders(body);
    shots.push(`**Shot ${no} (${timeRange}):**\n${body}`);
  }
}

collectByRegex(shotEnRegex);
if (shots.length === 0) collectByRegex(shotCnRegex);

const headerParts = [];
if (art) headerParts.push(`[Art Style] ${art}`);
if (render) headerParts.push(`[Render Quality] ${render}`);
if (mood) headerParts.push(`[Mood] ${mood}`);

const header = headerParts.length
  ? `${headerParts.join(', ')}.`
  : `[Art Style] UGC handheld, [Render Quality] mobile phone portrait 9:16, [Mood] authentic and persuasive.`;

const baseRules = cleanBlock(`
${header}
${language ? `Language: ${language}.` : ''}

Cinematic but authentic UGC pacing. Keep camera moves, timing, and beat order exactly as the shot list.
No watermark, no UI icons, no subtitles unless explicitly specified in the shot text.
Vertical 9:16, handheld realism, natural lighting.
`);

const soraBody = shots.length
  ? shots.join('\n\n')
  : cleanBlock(`(Fallback: could not parse shot blocks, using original content)\n\n${raw}`);

const soraPrompt = cleanBlock(`${baseRules}\n\n${soraBody}`);
const soraPromptCompact = cleanBlock(`
${header}
Vertical 9:16 UGC handheld realism. Keep timing and shot order.
${shots.length ? shots.join('\n') : raw}
`);

return [{
  json: {
    ...j,
    sora_prompt: soraPrompt,
    sora_prompt_compact: soraPromptCompact,
    shots_count: shots.length
  }
}];

